        "input": "审查以下 React Hooks 代码的问题：\n\nfunction UserProfile({ userId }) {\n  const [user, setUser] = useState(null);\n  const [todos, setTodos] = useState([]);\n  \n  useEffect(() => {\n    fetchUser(userId).then(setUser);\n    fetchTodos(userId).then(setTodos);\n  }, []);\n  \n  const handleClick = useCallback(() => {\n    console.log('User:', user);\n  }, []);\n  \n  return <div>...</div>;\n}",
        "output": "## React Hooks 代码审查报告\n\n### 🔴 问题分析\n\n#### 1. useEffect 依赖数组缺失\n**问题**: userId 变化时不会重新获取数据\n```javascript\n// ❌ 错误：依赖数组为空\nuseEffect(() => {\n  fetchUser(userId).then(setUser);\n  fetchTodos(userId).then(setTodos);\n}, []);\n\n// ✅ 修复：添加依赖\nuseEffect(() => {\n  fetchUser(userId).then(setUser);\n  fetchTodos(userId).then(setTodos);\n}, [userId]);\n```\n\n#### 2. 缺少清理函数\n**问题**: 组件卸载或 userId 变化时，未取消请求\n```javascript\n// ✅ 修复：添加清理\nuseEffect(() => {\n  let cancelled = false;\n  \n  fetchUser(userId).then(data => {\n    if (!cancelled) setUser(data);\n  });\n  \n  return () => {\n    cancelled = true;\n  };\n}, [userId]);\n```\n\n#### 3. useCallback 闭包陷阱\n**问题**: handleClick 捕获的是初始 user 值\n```javascript\n// ❌ 错误：依赖数组为空，user 永远是初始值\nconst handleClick = useCallback(() => {\n  console.log('User:', user);\n}, []);\n\n// ✅ 修复：添加 user 依赖\nconst handleClick = useCallback(() => {\n  console.log('User:', user);\n}, [user]);\n\n// 或使用 ref 获取最新值\nconst userRef = useRef(user);\nuseEffect(() => {\n  userRef.current = user;\n}, [user]);\n```\n\n### 📋 完整修复版本\n```javascript\nfunction UserProfile({ userId }) {\n  const [user, setUser] = useState(null);\n  const [todos, setTodos] = useState([]);\n  const [loading, setLoading] = useState(true);\n  \n  useEffect(() => {\n    let cancelled = false;\n    setLoading(true);\n    \n    Promise.all([\n      fetchUser(userId),\n      fetchTodos(userId)\n    ]).then(([userData, todoData]) => {\n      if (!cancelled) {\n        setUser(userData);\n        setTodos(todoData);\n        setLoading(false);\n      }\n    });\n    \n    return () => {\n      cancelled = true;\n    };\n  }, [userId]);\n  \n  const handleClick = useCallback(() => {\n    console.log('User:', user);\n  }, [user]);\n  \n  if (loading) return <div>Loading...</div>;\n  \n  return <div onClick={handleClick}>...</div>;\n}\n```"
