        "input": "用 Vue 3 Composition API 实现一个带搜索和分页的用户列表组件",
        "output": "## Vue 3 用户列表组件实现\n\n### 1. 创建 useUsers Composable\n```javascript\n// composables/useUsers.js\nimport { ref, computed, watch, onMounted } from 'vue';\nimport { debounce } from 'lodash-es';\n\nexport function useUsers() {\n  const users = ref([]);\n  const loading = ref(false);\n  const error = ref(null);\n  const total = ref(0);\n  \n  // 分页状态\n  const page = ref(1);\n  const pageSize = ref(20);\n  \n  // 搜索状态\n  const searchQuery = ref('');\n  \n  // 计算总页数\n  const totalPages = computed(() => \n    Math.ceil(total.value / pageSize.value)\n  );\n  \n  // 获取用户列表\n  const fetchUsers = async () => {\n    loading.value = true;\n    error.value = null;\n    \n    try {\n      const response = await fetch(\n        `/api/users?page=${page.value}&size=${pageSize.value}&q=${searchQuery.value}`\n      );\n      const data = await response.json();\n      users.value = data.items;\n      total.value = data.total;\n    } catch (err) {\n      error.value = err.message;\n    } finally {\n      loading.value = false;\n    }\n  };\n  \n  // 防抖搜索\n  const debouncedFetch = debounce(fetchUsers, 300);\n  \n  // 监听搜索变化\n  watch(searchQuery, () => {\n    page.value = 1; // 重置页码\n    debouncedFetch();\n  });\n  \n  // 监听分页变化\n  watch([page, pageSize], fetchUsers);\n  \n  // 初始加载\n  onMounted(fetchUsers);\n  \n  return {\n    users,\n    loading,\n    error,\n    page,\n    pageSize,\n    total,\n    totalPages,\n    searchQuery,\n    fetchUsers,\n    goToPage: (newPage) => page.value = newPage,\n    changePageSize: (newSize) => pageSize.value = newSize\n  };\n}\n```\n\n### 2. 组件实现\n```vue\n<!-- UserList.vue -->\n<template>\n  <div class=\"user-list\">\n    <!-- 搜索框 -->\n    <input \n      v-model=\"searchQuery\" \n      placeholder=\"搜索用户...\"\n      class=\"search-input\"\n    />\n    \n    <!-- 加载状态 -->\n    <div v-if=\"loading\" class=\"loading\">加载中...</div>\n    \n    <!-- 错误状态 -->\n    <div v-else-if=\"error\" class=\"error\">{{ error }}</div>\n    \n    <!-- 用户列表 -->\n    <ul v-else>\n      <li v-for=\"user in users\" :key=\"user.id\" class=\"user-item\">\n        <img :src=\"user.avatar\" :alt=\"user.name\" />\n        <span>{{ user.name }}</span>\n        <span>{{ user.email }}</span>\n      </li>\n    </ul>\n    \n    <!-- 分页 -->\n    <div class=\"pagination\" v-if=\"totalPages > 1\">\n      <button \n        @click=\"goToPage(page - 1)\" \n        :disabled=\"page === 1\"\n      >上一页</button>\n      \n      <span>第 {{ page }} / {{ totalPages }} 页</span>\n      \n      <button \n        @click=\"goToPage(page + 1)\" \n        :disabled=\"page === totalPages\"\n      >下一页</button>\n    </div>\n  </div>\n</template>\n\n<script setup>\nimport { useUsers } from '@/composables/useUsers';\n\nconst {\n  users,\n  loading,\n  error,\n  page,\n  totalPages,\n  searchQuery,\n  goToPage\n} = useUsers();\n</script>\n\n<style scoped>\n.user-list {\n  padding: 20px;\n}\n.search-input {\n  width: 100%;\n  padding: 10px;\n  margin-bottom: 20px;\n}\n.user-item {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 10px;\n  border-bottom: 1px solid #eee;\n}\n.pagination {\n  display: flex;\n  justify-content: center;\n  gap: 20px;\n  margin-top: 20px;\n}\n</style>\n```\n\n### 3. TypeScript 版本\n```typescript\n// composables/useUsers.ts\nimport { ref, computed, watch, onMounted } from 'vue';\n\ninterface User {\n  id: number;\n  name: string;\n  email: string;\n  avatar: string;\n}\n\ninterface UserListResponse {\n  items: User[];\n  total: number;\n}\n\nexport function useUsers() {\n  const users = ref<User[]>([]);\n  const loading = ref(false);\n  const error = ref<string | null>(null);\n  const total = ref(0);\n  const page = ref(1);\n  const pageSize = ref(20);\n  const searchQuery = ref('');\n  \n  const totalPages = computed(() => \n    Math.ceil(total.value / pageSize.value)\n  );\n  \n  const fetchUsers = async () => {\n    loading.value = true;\n    error.value = null;\n    \n    try {\n      const params = new URLSearchParams({\n        page: page.value.toString(),\n        size: pageSize.value.toString(),\n        q: searchQuery.value\n      });\n      \n      const response = await fetch(`/api/users?${params}`);\n      const data: UserListResponse = await response.json();\n      users.value = data.items;\n      total.value = data.total;\n    } catch (err) {\n      error.value = err instanceof Error ? err.message : 'Unknown error';\n    } finally {\n      loading.value = false;\n    }\n  };\n  \n  watch(searchQuery, () => {\n    page.value = 1;\n    fetchUsers();\n  });\n  \n  watch([page, pageSize], fetchUsers);\n  onMounted(fetchUsers);\n  \n  return {\n    users,\n    loading,\n    error,\n    page,\n    pageSize,\n    total,\n    totalPages,\n    searchQuery,\n    fetchUsers,\n    goToPage: (newPage: number) => page.value = newPage,\n    changePageSize: (newSize: number) => pageSize.value = newSize\n  };\n}\n```"
